// Physical Vehicle Component
instance PhysicalVehicle : DTDFVocab:Component [
    base:desc "1/10 scale teleoperated autonomous vehicle serving as the physical twin, retrofitted with advanced sensor and control technology, a dual‑tier chassis, and autonomous control elements."
]

// Sensing Components
instance LiDARSensor : DTDFVocab:SensingComponent [
    base:desc "LiDAR sensor mounted on vehicle, capturing point clouds of surrounding environment."
    DTDFVocab:producedData LiDARDataTransmitted
]

instance MotorActuationSensor : DTDFVocab:SensingComponent [
    base:desc "Sensor for motor actuation signals on the vehicle."
    DTDFVocab:producedData MotorActuationDataTransmitted
]

instance SteeringActuationSensor : DTDFVocab:SensingComponent [
    base:desc "Sensor for steering actuation signals on the vehicle."
    DTDFVocab:producedData SteeringActuationDataTransmitted
]

instance ServoActuationSensor : DTDFVocab:SensingComponent [
    base:desc "Sensor for servo actuation signals on the vehicle."
    DTDFVocab:producedData ServoActuationDataTransmitted
]

instance VehicleStateSensor : DTDFVocab:SensingComponent [
    base:desc "Sensor capturing derived vehicle state such as speed, acceleration, and heading."
    DTDFVocab:producedData VehicleStateDataTransmitted
]

// Data Transmitted
instance LiDARDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom LiDARSensor
]

instance MotorActuationDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorActuationSensor
]

instance SteeringActuationDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom SteeringActuationSensor
]

instance ServoActuationDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom ServoActuationSensor
]

instance VehicleStateDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom VehicleStateSensor
]

// Data Instances
instance LiDARPointCloudData : DTDFVocab:Data [
    base:desc "LiDAR point cloud data in vehicle coordinate system."
    DTDFVocab:fromData LiDARDataTransmitted
]

instance MotorActuationData : DTDFVocab:Data [
    base:desc "Motor actuation signal data."
    DTDFVocab:fromData MotorActuationDataTransmitted
]

instance SteeringActuationData : DTDFVocab:Data [
    base:desc "Steering actuation signal data."
    DTDFVocab:fromData SteeringActuationDataTransmitted
]

instance ServoActuationData : DTDFVocab:Data [
    base:desc "Servo actuation signal data."
    DTDFVocab:fromData ServoActuationDataTransmitted
]

instance VehicleStateData : DTDFVocab:Data [
    base:desc "Derived vehicle state data including speed, acceleration, and heading."
    DTDFVocab:fromData VehicleStateDataTransmitted
]

instance ObjectTrackData : DTDFVocab:Data [
    base:desc "Dynamic tracks of surrounding objects extracted from LiDAR point cloud clustering."
    DTDFVocab:fromData LiDARPointCloudData
]

// Enablers
instance DataTranslationEnabler : DTDFVocab:Enabler [
    base:desc "Data Translation component that serializes, aligns message types, and performs unit conversions for all vehicle sensor data streams."
    DTDFVocab:inputTo LiDARPointCloudData, MotorActuationData, SteeringActuationData, ServoActuationData, VehicleStateData
    DTDFVocab:enables DataMonitoringService
]

instance PointCloudClusteringEnabler : DTDFVocab:Enabler [
    base:desc "Point Cloud Clustering & Tracking sub‑service that extracts and tracks object tracks from LiDAR point clouds."
    DTDFVocab:inputTo LiDARPointCloudData
    DTDFVocab:enables ROS2NetworkEnabler
]

instance ROS2NetworkEnabler : DTDFVocab:Enabler [
    base:desc "ROS2 network component that transmits processed point clouds, object tracks, and vehicle state over an internal network to 3D Visualization and Data Monitoring services."
    DTDFVocab:inputTo LiDARPointCloudData, VehicleStateData, ObjectTrackData
    DTDFVocab:enables DataMonitoringService, RemoteManagementService
]

instance ACCComputationEnabler : DTDFVocab:Enabler [
    base:desc "Computation Offloading enabler that runs the Adaptive Cruise Control algorithm on vehicle state and object tracks, returning speed commands to the on‑board ECU."
    DTDFVocab:inputTo VehicleStateData, ObjectTrackData
    DTDFVocab:enables ComputationOffloadingService
]

// Services
instance DataMonitoringService : DTDFVocab:Service [
    base:desc "Data Monitoring service providing real‑time vehicle state, projected trajectory, and dynamic object tracks for operators."
