]

instance ComputationOffloadingService : DTDFVocab:Service [
    base:desc "Computing Offloading service that runs the ACC algorithm and returns speed commands to the vehicle ECU, relieving the vehicle of heavy processing."
    DTDFVocab:provides SpeedCommandAction
]

instance RemoteManagementService : DTDFVocab:Service [
    base:desc "Remote Management service that allows operators to enable/disable ACC, set desired speed, or trigger an emergency brake."
    DTDFVocab:provides ACCEnableAction, DesiredSpeedSetAction, EmergencyBrakeAction
